#include <iostream>
#include <string>
#include <algorithm>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;

    string rev = s;
    reverse(rev.begin(), rev.end());

    if (s == rev) {
        cout << "YES\n";
    } else {
        cout << "NO\n";
    }

    return 0;
}
